#include "DataParser.hpp"
#include "../tools/tools.hpp"
#include <arpa/inet.h>

#include "../tools/log/log.h"
#include "../tools/string/StringUtils.h"

extern const char * const bleDoubleAuthMessageHeader = "doublesidedAuth";
extern const char * const pollingMessageHeader = "polling";
extern const char * const bleRequestLocationMessageHeader = "startRequestBleLocation";
extern const char * const bleRequestDisconnectMessageHeader = "requestDisconnect";
extern const char * const doorHandleMessageHeader = "doorHandle";

void DataParser::buildCdcuLoginMessage(CdcuLoginMessage *loginMessage) {
    kCarEventStart(cdcuLogin, cdcuLoginMessageHeader)
    kAddUInt8ItemToJson(cdcuLogin, "signalValue", loginMessage->loginState);
    kAddUInt8ItemToJson(cdcuLogin, "errorCode", loginMessage->errorCode);
    kCarEventEnd(cdcuLogin, this->resultArray)
}

void DataParser::buildBleDoubleAuthMessage(BleDoubleAuthMessage *doubleAuthMessage) {
    kCarEventStart(doubleAuth, bleDoubleAuthMessageHeader)
    kAddUInt8ItemToJson(doubleAuth, "frameIndex", doubleAuthMessage->frameIndex);
    kAddUInt8ItemToJson(doubleAuth, "frameCount", doubleAuthMessage->frameCount);
    kAddUInt64ItemToJson(doubleAuth, "data", doubleAuthMessage->data);
    kCarEventEnd(doubleAuth, this->resultArray)
}

void DataParser::buildPollingMessage(PollingMessage *pollingMessage) {
    kVehicleStateStart(polling)
    kAddUInt8ItemToJson(polling, "driverSeatOccupied", pollingMessage->driverSeatOccupied);
    kAddUInt8ItemToJson(polling, "alarmState", pollingMessage->alarmState);
    kAddUInt8ItemToJson(polling, "powerMode", pollingMessage->powerMode);
    kAddUInt8ItemToJson(polling, "trunkReleaseState", pollingMessage->trunkReleaseState);
    kAddUInt8ItemToJson(polling, "sleepModeState", pollingMessage->sleepModeState);
    kAddUInt8ItemToJson(polling, "tBox4GState", pollingMessage->tBox4GState);
    kAddUInt8ItemToJson(polling, "unlockSource", pollingMessage->unlockSource);
    kAddUInt8ItemToJson(polling, "lockSource", pollingMessage->lockSource);
    kAddUInt8ItemToJson(polling, "slowChargePortReleaseState", pollingMessage->slowChargePortReleaseState);
    kAddUInt8ItemToJson(polling, "fastChargePortReleaseState", pollingMessage->fastChargePortReleaseState);
    kVehicleStateEnd(pollingMessageHeader, polling, this->resultArray)
}

void DataParser::buildBleRequestLoactionMessage(BleRequestLoactionMessage *requestMessage) {
    kCarEventStart(locationRequest, bleRequestLocationMessageHeader)
    kAddUInt8ItemToJson(locationRequest, "signalValue", requestMessage->singalValue);
    kCarEventEnd(locationRequest, this->resultArray)
}

void DataParser::buildBleRequestDisconnectMessage(BleRequestDisconnectMessage *disconnectMessage) {
    kCarEventStart(bleDisconnect, bleRequestDisconnectMessageHeader)
    kAddUInt8ItemToJson(bleDisconnect, "value", disconnectMessage->value);
    kCarEventEnd(bleDisconnect, this->resultArray)
}

void DataParser::buildDoorHandleMessage(DoorHandleMessage *doorHandleMessage) {
    kVehicleStateStart(doorHandle)
    kAddUInt8ItemToJson(doorHandle, "flHandlePosState", doorHandleMessage->flHandlePosState);
    kAddUInt8ItemToJson(doorHandle, "frHandlePosState", doorHandleMessage->frHandlePosState);
    kAddUInt8ItemToJson(doorHandle, "rlHandlePosState", doorHandleMessage->rlHandlePosState);
    kAddUInt8ItemToJson(doorHandle, "rrHandlePosState", doorHandleMessage->rrHandlePosState);
    kVehicleStateEnd(doorHandleMessageHeader, doorHandle, this->resultArray)
}


void DataParser::config(const uint8_t* data, size_t dataSize) {
    if (dataSize == 0) {
        return;
    }
    // 取前两个字节的数据并转换字节序
    uint8_t* typeData = subdata(data, 0, 2);

    type = (BleCanType)ntohs(*reinterpret_cast<uint16_t*>(typeData));

